    # -------------------------------------------------------------------------
    # High-level multi-tenant setup
    # -------------------------------------------------------------------------

    def setup_tenant(
        self,
        tenant_name: str,
        description: str = "",
        app_users: Optional[list] = None,
        exchanges: Optional[list] = None,
        queues: Optional[list] = None,
        bindings: Optional[list] = None,
    ):
        """
        Set up a complete tenant environment with vhost, users, permissions,
        exchanges, queues, and bindings.

        Args:
            tenant_name: Name of the tenant (used as vhost name).
            description: Description of the tenant.
            app_users: List of dicts with keys: username, password, tags, permissions.
            exchanges: List of dicts with keys: name, type, durable.
            queues: List of dicts with keys: name, durable, arguments.
            bindings: List of dicts with keys: exchange, queue, routing_key.
        """
        print(f"\n{'='*60}")
        print(f"Setting up tenant: {tenant_name}")
        print(f"{'='*60}")

        # 1. Create the vhost
        vhost = RabbitMQVhost(
            name=tenant_name,
            description=description,
            tags=["multi-tenant"],
        )
        self.create_vhost(vhost)

        # 2. Set up HA / message TTL policies for the vhost
        self.set_policy(
            vhost_name=tenant_name,
            policy_name=f"{tenant_name}-ha-policy",
            pattern=".*",
            definition={
                "ha-mode": "all",
                "ha-sync-mode": "automatic",
            },
            priority=0,
            apply_to="queues",
        )

        # 3. Create users and set permissions
        if app_users:
            for user_config in app_users:
                user = RabbitMQUser(
                    username=user_config["username"],
                    password=user_config["password"],
                    tags=user_config.get("tags", ""),
                )
                self.create_user(user)

                perm_config = user_config.get("permissions", {})
                permission = RabbitMQPermission(
                    configure=perm_config.get("configure", ".*"),
                    write=perm_config.get("write", ".*"),
                    read=perm_config.get("read", ".*"),
                )
                self.set_permissions(user.username, tenant_name, permission)

        # 4. Create exchanges
        if exchanges:
            for exc in exchanges:
                self.create_exchange(
                    vhost_name=tenant_name,
                    exchange_name=exc["name"],
                    exchange_type=exc.get("type", "topic"),
                    durable=exc.get("durable", True),
                )

        # 5. Create queues
        if queues:
            for q in queues:
                self.create_queue(
                    vhost_name=tenant_name,
                    queue_name=q["name"],
                    durable=q.get("durable", True),
                    arguments=q.get("arguments", {}),
                )

        # 6. Create bindings
        if bindings:
            for b in bindings:
                self.create_binding(
                    vhost_name=tenant_name,
                    exchange_name=b["exchange"],
                    queue_name=b["queue"],
                    routing_key=b.get("routing_key", ""),
                )

        print(f"\n[DONE] Tenant '{tenant_name}' setup complete.\n")

    def print_summary(self):
        """Print a summary of all vhosts, users, and permissions."""
        print(f"\n{'='*60}")
        print("RabbitMQ Configuration Summary")
        print(f"{'='*60}")

        # Vhosts
        vhosts = self.list_vhosts()
        print(f"\n--- Virtual Hosts ({len(vhosts)}) ---")
        for vh in vhosts:
            name = vh.get("name", "unknown")
            desc = vh.get("description", "")
            messages = vh.get("messages", 0)
            print(f"  • {name} - {desc} (messages: {messages})")

        # Users
        users = self.list_users()
        print(f"\n--- Users ({len(users)}) ---")
        for u in users:
            username = u.get("name", "unknown")
            tags = u.get("tags", "")
            print(f"  • {username} (tags: {tags or 'none'})")

        # Permissions
        permissions = self.get_permissions()
        print(f"\n--- Permissions ({len(permissions)}) ---")
        for p in permissions:
            print(f"  • User '{p.get('user')}' on vhost '{p.get('vhost')}': "
                  f"configure='{p.get('configure')}', "
                  f"write='{p.get('write')}', "
                  f"read='{p.get('read')}'")

        print(f"\n{'='*60}\n")


